function lookup.NormalizeTitle(title)
    if type(title) ~= "string" then
        return nil
    end

    title = title:gsub("^%s+", "")
    title = title:gsub("%s+$", "")
    title = title:gsub("%s+", " ")
    title = string.lower(title)
    if title == "" then
        return nil
    end

    return title
end

function lookup.GetTypeByQuestId(questId)
    questId = tonumber(questId)
    if not questId or questId <= 0 then
        return nil
    end

    return lookup.byQuestId[questId]
end

function lookup.GetTypeByTitle(title)
    local normalized = lookup.NormalizeTitle(title)
    if not normalized then
        return nil
    end

    return lookup.byNormalizedTitle[normalized]
end

function lookup.Resolve(questId, title)
    return lookup.GetTypeByQuestId(questId) or lookup.GetTypeByTitle(title)
end

function lookup.IsRecurring(questId, title)
    return lookup.Resolve(questId, title) ~= nil
end
